import ast
from dataclasses import dataclass

@dataclass
class ParseResult:
    valid: bool
    tree: ast.Module | None
    error: str | None
    error_line: int | None

def parse_python(source: str) -> ParseResult:
    try:
        tree = ast.parse(source)
        return ParseResult(valid=True, tree=tree, error=None, error_line=None)
    except SyntaxError as e:
        return ParseResult(
            valid=False,
            tree=None,
            error=str(e.msg),
            error_line=e.lineno,
        )

def find_undefined_names(source: str, tree: ast.Module) -> list[str]:
    """Names used in the code but never assigned or imported."""
    defined: set[str] = set()
    used: set[str] = set()
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            defined.add(node.name)
        elif isinstance(node, ast.Name):
            if isinstance(node.ctx, ast.Store):
                defined.add(node.id)
            elif isinstance(node.ctx, ast.Load):
                used.add(node.id)
        elif isinstance(node, ast.Import):
            for alias in node.names:
                defined.add(alias.asname or alias.name)
        elif isinstance(node, ast.ImportFrom):
            for alias in node.names:
                defined.add(alias.asname or alias.name)
    builtins = set(dir(__builtins__)) if isinstance(__builtins__, dict) else set(dir(__builtins__))
    return sorted(used - defined - builtins)

def format_diagnostics(diags: list[Diagnostic]) -> str:
    # Sort errors before warnings, then by line number
    diags = sorted(diags, key=lambda d: (0 if d.severity == "error" else 1, d.line))
    lines = []
    for d in diags:
        lines.append(f"  Line {d.line}, col {d.col}: [{d.code}] {d.message} ({d.severity})")
    return "\n".join(lines)

def build_fix_prompt(original_code: str, diags: list[Diagnostic]) -> list[dict]:
    diag_text = format_diagnostics(diags)
    return [
        {
            "role": "system",
            "content": (
                "You are a code repair assistant. "
                "Fix ONLY the issues listed in the diagnostics. "
                "Do not change any other part of the code. "
                "Return the complete corrected file with no explanation."
            ),
        },
        {
            "role": "user",
            "content": (
                f"Fix the following Python code based on these diagnostics:\n\n"
                f"DIAGNOSTICS:\n{diag_text}\n\n"
                f"CODE:\n```python\n{original_code}\n```\n\n"
                f"Return only the corrected code, no markdown fences."
            ),
        },
    ]

import ast
import astor  # pip install astor — converts AST back to source

class RemoveUnusedImports(ast.NodeTransformer):
    """
    Removes import statements for names that are never referenced
    in the rest of the module. A quick substitute for autoflake.
    """
    def __init__(self, used_names: set[str]):
        self.used = used_names

    def visit_Import(self, node: ast.Import) -> ast.Import | None:
        node.names = [
            alias for alias in node.names
            if (alias.asname or alias.name.split(".")[0]) in self.used
        ]
        return node if node.names else None

    def visit_ImportFrom(self, node: ast.ImportFrom) -> ast.ImportFrom | None:
        node.names = [
            alias for alias in node.names
            if (alias.asname or alias.name) in self.used
        ]
        return node if node.names else None

def remove_unused_imports(source: str) -> str:
    tree = ast.parse(source)
    used: set[str] = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Name):
            used.add(node.id)
        elif isinstance(node, ast.Attribute):
            # top-level module reference (e.g. os.path → os)
            if isinstance(node.value, ast.Name):
                used.add(node.value.id)
    transformer = RemoveUnusedImports(used)
    new_tree = transformer.visit(tree)
    ast.fix_missing_locations(new_tree)
    return astor.to_source(new_tree)
